BEGIN;
DO $$
DECLARE
  v_prop uuid; v_user uuid; v_rec uuid; v_res uuid; v_lob uuid; v_rep uuid;
  v_cash_net numeric; v_pos_net numeric;
BEGIN
  SELECT id INTO v_prop FROM properties WHERE name ILIKE '%ривърсайд%' LIMIT 1;
  SELECT id INTO v_user FROM user_profiles LIMIT 1;
    ON CONFLICT (property_id, name) DO NOTHING;
  SELECT id INTO v_rec FROM departments WHERE property_id=v_prop AND name='Рецепция';
  SELECT id INTO v_res FROM departments WHERE property_id=v_prop AND name='Ресторант';
  SELECT id INTO v_lob FROM departments WHERE property_id=v_prop AND name='Лоби Бар';
  RAISE NOTICE 'rec=% res=% lob=%', v_rec, v_res, v_lob;

END $$;
COMMIT;
